/* Circular Dials styling */
.dials-container {
  display: flex;
  justify-content: space-around;
  align-items: center;
  border-top: 1px solid var(--hairline-soft);
  padding-top: 12px;
  margin-top: 12px;
  margin-bottom: 12px;
}
.dial-box {
  display: flex;
  flex-direction: column;
  align-items: center;
  position: relative;
}
.dial-box svg {
  transform: rotate(-90deg);
}
.dial-box circle {
  fill: none;
  stroke-width: 4px;
}
.dial-box .dial-bg {
  stroke: var(--hairline);
}
.dial-box .dial-fill {
  stroke-dasharray: 150.8;
  stroke-dashoffset: 150.8;
  transition: stroke-dashoffset 0.4s cubic-bezier(0.4, 0, 0.2, 1), stroke 0.4s ease;
}
.dial-label {
  position: absolute;
  top: 18px;
  left: 0;
  right: 0;
  text-align: center;
  font-family: 'JetBrains Mono', monospace;
  font-size: 10px;
  font-weight: 700; 
  color: var(--ink);
}

/* Chaos Monkey Console */
.chaos-console {
  background: rgba(0, 0, 0, 0.85) !important;
  border: 1px solid var(--hairline) !important;
  color: #10b981 !important;
  font-family: 'JetBrains Mono', monospace;
  padding: 10px;
  border-radius: 8px;
  height: 110px;
  overflow-y: auto;
  font-size: 10px;
  line-height: 1.5;
  box-shadow: inset 0 2px 8px rgba(0,0,0,0.8);
  text-align: left;
}
.chaos-console .log-err {
  color: #ff4b4b;
}
.chaos-console .log-warn {
  color: #ffa726;
}
.chaos-console .log-info {
  color: #0099ff;
}
.chaos-console .log-success {
  color: #10b981;
}

/* Chaos Monkey Buttons */
.chaos-btn {
  background: var(--surface-1);
  border: 1px solid var(--hairline);
  color: var(--ink);
  cursor: pointer;
  transition: all 0.2s ease;
  font-family: 'Outfit', sans-serif;
  font-weight: 500;
}
.chaos-btn:hover {
  background: var(--surface-2);
  border-color: var(--ink-muted);
  transform: translateY(-1px);
}
.chaos-btn:active {
  transform: translateY(0);
}

/* Raft Ledger Table */
#raftTableContainer::-webkit-scrollbar {
  width: 4px;
}
#raftTableContainer::-webkit-scrollbar-track {
  background: transparent;
}
#raftTableContainer::-webkit-scrollbar-thumb {
  background: var(--hairline);
  border-radius: 2px;
}
#raftTableContainer table th, #raftTableContainer table td {
  border-bottom: 1px solid var(--hairline-soft);
  padding: 6px 8px;
}
#raftTableContainer table tbody tr:hover {
  background: rgba(255, 255, 255, 0.02);
}

/* Ledger Badges */
.ledger-badge {
  display: inline-block;
  padding: 2px 6px;
  border-radius: 4px;
  font-size: 8px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  text-align: center;
  min-width: 65px;
}
.ledger-uncommitted {
  background: rgba(255, 167, 38, 0.1);
  color: #ffa726;
  border: 1px solid rgba(255, 167, 38, 0.2);
}
.ledger-replicated {
  background: rgba(0, 153, 255, 0.1);
  color: #0099ff;
  border: 1px solid rgba(0, 153, 255, 0.2);
}
.ledger-committed {
  background: rgba(16, 185, 129, 0.1);
  color: #10b981;
  border: 1px solid rgba(16, 185, 129, 0.2);
}
.ledger-offline {
  background: rgba(255, 75, 75, 0.1);
  color: #ff4b4b;
  border: 1px solid rgba(255, 75, 75, 0.2);
}
.ledger-stale {
  background: rgba(142, 142, 147, 0.1);
  color: #8e8e93;
  border: 1px solid rgba(142, 142, 147, 0.2);
}

/* System Architecture Diagram Container */
.arch-diagram-wrapper {
  position: relative;
  border: 1px solid var(--hairline);
  background: var(--surface-trans);
  border-radius: 10px;
  overflow: hidden;
  margin-bottom: 1.75rem;
}
.arch-viewport-container {
  width: 100%;
  height: 280px;
  cursor: grab;
  overflow: hidden;
  position: relative;
}
.arch-viewport-container:active {
  cursor: grabbing;
}
.arch-controls {
  position: absolute; 
  top: 12px;
  right: 12px;
  display: flex;
  gap: 6px;
  z-index: 10;
}
.arch-ctrl-btn {
  width: 28px;
  height: 28px;
  background: var(--surface-2);
  border: 1px solid var(--hairline);
  border-radius: 6px;
  color: var(--ink);
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  font-size: 14px;
  transition: all 0.2s ease;
}
.arch-ctrl-btn:hover {
  background: var(--primary);
  color: var(--on-primary);
  border-color: var(--primary);
}

/* SVG Node Interactivity */
.arch-node {
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  cursor: pointer;
}
.arch-node:hover {
  filter: drop-shadow(0 0 8px rgba(0, 153, 255, 0.6));
}
.arch-node.active {
  filter: drop-shadow(0 0 12px rgba(212, 77, 240, 0.8));
}

/* SVG Connection Heartbeats & Lines */
.heartbeat-active {
  stroke-dasharray: 4;
  animation: svgHeartbeat 1.5s linear infinite;
  stroke: var(--accent-blue);
  stroke-width: 2px;
}
.heartbeat-partitioned {
  stroke-dasharray: 2 4;
  stroke: #ffa726;
  stroke-width: 1.5px;
  opacity: 0.4;
  animation: none;
}
.heartbeat-broken {
  stroke: #ff4b4b;
  stroke-width: 1px;
  stroke-dasharray: 1 5;
  opacity: 0.2;
  animation: none;
}
@keyframes svgHeartbeat {
  to {
    stroke-dashoffset: -20;
  }
}

/* Arch Info Card */
.arch-info-card {
  border-top: 1px solid var(--hairline);
  background: rgba(0, 0, 0, 0.25);
  padding: 16px;
  text-align: left;
  min-height: 90px;
}
.arch-info-title {
  font-family: 'Outfit', sans-serif;
  font-size: 13px;
  font-weight: 700;
  color: var(--primary);
  margin-bottom: 4px;
}
.arch-info-desc {
  font-size: 11.5px;
  color: var(--ink-muted);
  line-height: 1.5;
}

/* API Key Console Container */
.api-key-console {
  display: grid;
  grid-template-columns: 1.2fr 1.8fr;
  gap: 20px;
  border: 1px solid var(--hairline);
  background: var(--surface-trans);
  border-radius: 10px;
  padding: 20px;
  margin-bottom: 1.75rem;
  text-align: left;
}
@media (max-width: 768px) {
  .api-key-console {
    grid-template-columns: 1fr;
  }
}
.api-field-group {
  margin-bottom: 14px;
}
.api-field-group label {
  display: block;
  font-size: 10px;
  font-weight: 700;
  color: var(--ink-muted);
  text-transform: uppercase;
  margin-bottom: 6px;
}
.api-input-text {
  width: 100%;
  background: var(--input-bg);
  border: 1px solid var(--input-border);
  color: var(--ink);
  padding: 8px 12px;
  font-size: 12px;
  border-radius: 6px;
  font-family: 'JetBrains Mono', monospace;
}
.api-input-text:focus {
  background: var(--input-bg-focus);
  border-color: var(--accent-blue);
  outline: none;
}

/* Sliders customizer styling */
.customizer-slider-group {
  margin-bottom: 14px;
  text-align: left;
}
.customizer-slider-header {
  display: flex;
  justify-content: space-between;
  font-size: 11px;
  font-weight: 600;
  color: var(--ink-muted);
  margin-bottom: 4px;
}
.customizer-slider-val {
  font-family: 'JetBrains Mono', monospace;
  color: var(--ink);
  font-weight: 700;
}
.customizer-input-range {
  width: 100%;
  height: 4px;
  background: var(--surface-2);
  border-radius: 2px;
  outline: none;
  -webkit-appearance: none;
}
.customizer-input-range::-webkit-slider-thumb {
  -webkit-appearance: none;
  width: 12px;
  height: 12px;
  border-radius: 50%;
  background: var(--primary);
  cursor: pointer;
  transition: transform 0.1s ease;
}
.customizer-input-range::-webkit-slider-thumb:hover {
  transform: scale(1.2);
}

/* Cluster Sim Grid */
.cluster-sim-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(320px, 1fr));
  gap: 20px;
  margin-bottom: 24px;
}

/* Privacy Accordion styling */
.privacy-accordion-header {
  border: 1px solid var(--hairline);
  background: var(--surface-trans);
  border-radius: 8px;
  padding: 16px;
  cursor: pointer;
  display: flex;
  justify-content: space-between;
  align-items: center;
  transition: all 0.2s ease;
  margin-bottom: 12px;
  text-align: left;
}
.privacy-accordion-header:hover {
  background: var(--surface-2);
  border-color: var(--ink-muted);
}
.privacy-accordion-body {
  border: 1px solid var(--hairline);
  border-top: none;
  background: rgba(0, 0, 0, 0.2);
  border-radius: 0 0 8px 8px;
  padding: 20px;
  margin-top: -12px;
  margin-bottom: 1.75rem;
  text-align: left;
  line-height: 1.6;
}
.privacy-item {
  margin-bottom: 16px;
}
.privacy-item:last-child {
  margin-bottom: 0;
}
.privacy-item-title {
  font-family: 'Outfit', sans-serif;
  font-size: 12.5px;
  font-weight: 700;
  color: var(--primary);
  display: flex; 
  align-items: center;
  gap: 8px;
  margin-bottom: 4px;
}
.privacy-item-desc {
  font-size: 11.5px;
  color: var(--ink-muted);
}

