// System Architecture Zoom & Pan State
let archZoom = 1;
let archPanX = 0;
let archPanY = 0;
let isPanning = false;
let startX = 0, startY = 0;

window.handleArchZoom = function(e) {
  e.preventDefault();
  const zoomFactor = 0.08;
  if (e.deltaY < 0) {
    archZoom = Math.min(archZoom + zoomFactor, 2.5);
  } else {
    archZoom = Math.max(archZoom - zoomFactor, 0.5);
  }
  updateArchTransform();
};

window.handleArchPanStart = function(e) {
  if (e.target.closest('.arch-controls')) return;
  isPanning = true;
  startX = e.clientX - archPanX;
  startY = e.clientY - archPanY;
  document.addEventListener('mousemove', handleArchPanMove);
  document.addEventListener('mouseup', handleArchPanEnd);
};

function handleArchPanMove(e) {
  if (!isPanning) return;
  archPanX = e.clientX - startX;
  archPanY = e.clientY - startY;
  updateArchTransform();
}

function handleArchPanEnd() {
  isPanning = false;
  document.removeEventListener('mousemove', handleArchPanMove);
  document.removeEventListener('mouseup', handleArchPanEnd);
}

window.zoomArchIn = function() {
  if (typeof playClickSound === 'function') playClickSound();
  archZoom = Math.min(archZoom + 0.15, 2.5);
  updateArchTransform();
};

window.zoomArchOut = function() {
  if (typeof playClickSound === 'function') playClickSound();
  archZoom = Math.max(archZoom - 0.15, 0.5);
  updateArchTransform();
};

window.resetArchZoom = function() {
  if (typeof playClickSound === 'function') playClickSound();
  archZoom = 1;
  archPanX = 0;
  archPanY = 0;
  updateArchTransform();
};

function updateArchTransform() {
  const g = document.getElementById('archG');
  if (g) {
    g.setAttribute('transform', `translate(${archPanX}, ${archPanY}) scale(${archZoom})`);
  }
}

